class Solution:
    def isValid(self, s: str) -> bool:
        stack = []
        closeToOpen = {')': '(', ']': '[', '}': '{'}

        for c in s:
            if c in closeToOpen:  # it's a closing bracket
                if not stack or stack[-1] != closeToOpen[c]:
                    return False
                stack.pop()
            else:  # it's an opening bracket
                stack.append(c)

        return not stack  # valid only if all openers were closed

class MinStack:
    def __init__(self):
        self.stack = []
        self.min_stack = []  # min_stack[i] = min of stack[0..i]

    def push(self, val: int) -> None:
        self.stack.append(val)
        # new min is either val or the previous min, whichever is smaller
        new_min = val if not self.min_stack else min(val, self.min_stack[-1])
        self.min_stack.append(new_min)

    def pop(self) -> None:
        self.stack.pop()
        self.min_stack.pop()

    def top(self) -> int:
        return self.stack[-1]

    def getMin(self) -> int:
        return self.min_stack[-1]

class Solution:
    def evalRPN(self, tokens: list[str]) -> int:
        stack = []
        ops = {'+', '-', '*', '/'}

        for t in tokens:
            if t in ops:
                b = stack.pop()  # right operand
                a = stack.pop()  # left operand
                if t == '+':
                    stack.append(a + b)
                elif t == '-':
                    stack.append(a - b)
                elif t == '*':
                    stack.append(a * b)
                else:  # '/'
                    stack.append(int(a / b))  # truncate toward zero
            else:
                stack.append(int(t))

        return stack[0]

class Solution:
    def dailyTemperatures(self, temperatures: list[int]) -> list[int]:
        n = len(temperatures)
        res = [0] * n
        for i in range(n):
            for j in range(i + 1, n):
                if temperatures[j] > temperatures[i]:
                    res[i] = j - i
                    break
        return res

class Solution:
    def dailyTemperatures(self, temperatures: list[int]) -> list[int]:
        n = len(temperatures)
        res = [0] * n
        stack = []  # stores indices

        for i in range(n):
            # while current temp is warmer than the temp at stack top
            while stack and temperatures[i] > temperatures[stack[-1]]:
                prev_i = stack.pop()
                res[prev_i] = i - prev_i
            stack.append(i)

        return res

class Solution:
    def carFleet(self, target: int, position: list[int], speed: list[int]) -> int:
        # pair each car's (position, time_to_target), sort by position descending
        pairs = [(p, (target - p) / s) for p, s in zip(position, speed)]
        pairs.sort(reverse=True)  # start from the car closest to target

        stack = []  # stores times-to-target of fleet leaders
        for pos, time in pairs:
            # if this car's time > top of stack, it's a new fleet (can't catch the one ahead)
            if not stack or time > stack[-1]:
                stack.append(time)
            # else: time <= stack[-1] means it catches the fleet ahead; no new fleet

        return len(stack)

