class Solution:
    def removeDuplicateLetters(self, s: str) -> str:
        charToLastIndexMap = defaultdict(int)
        for index, char in enumerate(s):
            charToLastIndexMap[char] = index

        stack, visited = [], set()
        for index, char in enumerate(s):
            if char not in visited:
                while stack and stack[-1]>char and charToLastIndexMap[stack[-1]]>index: # if it can be added later, add later
                    visited.remove(stack.pop())
                stack.append(char)
                visited.add(char)
        return ''.join(stack)

class StockSpanner:

    def __init__(self):
        self.stack = [(0,-1)]
        self.nextIndex = 0

    def next(self, price: int) -> int:

        while len(self.stack)>1 and price>=self.stack[len(self.stack)-1][0]:
            self.stack.pop()

        span = self.nextIndex - self.stack[len(self.stack)-1][1]
        self.stack.append((price,self.nextIndex))
        self.nextIndex += 1
        return span

# Key Idea 1: Max Length ending at index will depend on max length ending before the current match
#            (())() => dp[5] depends on dp[3]
# Key Idea 2: Use stacks to keep track of unused '(' to match with ')' [in our example index 4]
# Key Idea 3: Stack top's index will be just right of prev ')' [in our example index 3]

class Solution:
    def longestValidParentheses(self, s: str) -> int:
        dp, stack = [0] * (len(s)+1), []
        for index, char in enumerate(s):
            if char=='(':
                stack.append(index)
            else:
                if stack:
                    prevIndex = stack.pop()
                    dp[index+1] = dp[prevIndex] + (index - prevIndex + 1)
        return max(dp)

class Solution:
    def largestRectangleArea(self, heights: list[int]) -> int:
        max_area = 0
        n = len(heights)
        for i in range(n):
            min_h = heights[i]
            for j in range(i, n):
                min_h = min(min_h, heights[j])
                max_area = max(max_area, min_h * (j - i + 1))
        return max_area

class Solution:
    def largestRectangleArea(self, heights: list[int]) -> int:
        stack = []  # stores (index, height) pairs
        max_area = 0

        for i, h in enumerate(heights):
            start = i
            # pop all bars taller than current (they're closed by this shorter bar)
            while stack and stack[-1][1] > h:
                idx, height = stack.pop()
                max_area = max(max_area, height * (i - idx))
                start = idx  # current bar can extend back to this popped bar's start
            stack.append((start, h))

        # process remaining bars in stack (they extend to the end)
        for idx, height in stack:
            max_area = max(max_area, height * (len(heights) - idx))

        return max_area
